// Template: instagram-profile
// Description: No description available
// Scene: Scene 1

import { AbsoluteFill, spring, interpolate, useCurrentFrame, useVideoConfig, Img, Audio, Sequence, Loop, OffthreadVideo } from "remotion";
import React from "react";

const SCENE_PARAMS = {
  profileImage: { type: "image", label: "Profile Image", value: "data:image/jpeg;base64," },
  profileName: { type: "text", label: "Profile Name", value: "artzenmedia" },
  posts: { type: "text", label: "Posts", value: "178" },
  followers: { type: "text", label: "Followers", value: "143K" },
  following: { type: "text", label: "Following", value: "275" },
  bio: { type: "multilineText", label: "Bio", value: "Helping you make better content\nEditing tips / tutorials and social media" },
  fontFamily: { type: "font", label: "Font", value: "Inter" },
  backgroundColor: { type: "color", label: "Background", value: "#ffffff" },
  textColor: { type: "color", label: "Text", value: "#000000" },
  secondaryColor: { type: "color", label: "Secondary Text", value: "#737373" },
  accentColor: { type: "color", label: "Follow Button", value: "#3b82f6" },
  buttonBgColor: { type: "color", label: "Button Background", value: "#e5e5e5" },
  scale: { type: "number", label: "Scale", value: 0.95, min: 0.5, max: 2, step: 0.05 },
  animationSpeed: { type: "number", label: "Animation Speed", value: 1, min: 0.5, max: 2, step: 0.1 },
  staggerDelay: { type: "number", label: "Stagger Delay", value: 6, min: 2, max: 15, step: 1 }
};

function Scene(props: any) {
  const frame = useCurrentFrame();
  const { fps, width, height } = useVideoConfig();
  const minDim = Math.min(width, height);
  const adjustedFrame = frame * (props.animationSpeed ?? SCENE_PARAMS.animationSpeed.value);
  const stagger = (props.staggerDelay ?? SCENE_PARAMS.staggerDelay.value);

  const fadeIn = (delay) => {
    const progress = spring({ frame: Math.max(0, adjustedFrame - delay), fps, config: { damping: 20, stiffness: 90 } });
    return progress;
  };

  const slideUp = (delay) => {
    const progress = fadeIn(delay);
    return interpolate(progress, [0, 1], [15, 0]);
  };

  const avatarProgress = fadeIn(0);
  const avatarScale = interpolate(avatarProgress, [0, 1], [0.8, 1]);
  
  const nameProgress = fadeIn(stagger);
  const statsProgress = fadeIn(stagger * 2);
  const bioProgress = fadeIn(stagger * 4);
  const buttonsProgress = fadeIn(stagger * 6);

  const avatarSize = minDim * 0.18;
  const containerWidth = minDim * 0.85;

  const bioLines = (props.bio ?? SCENE_PARAMS.bio.value).split('\n');

  return (
    <AbsoluteFill style={{ backgroundColor: (props.backgroundColor ?? SCENE_PARAMS.backgroundColor.value), justifyContent: "center", alignItems: "center" }}>
      <div style={{ transform: "scale(" + (props.scale ?? SCENE_PARAMS.scale.value) + ")", transformOrigin: "center center", width: containerWidth, padding: minDim * 0.05 }}>
        
        {/* Header Row - Avatar + Name + Stats */}
        <div style={{ display: "flex", alignItems: "flex-start", gap: minDim * 0.04, marginBottom: minDim * 0.05 }}>
          
          {/* Avatar with Image */}
          <div style={{
            width: avatarSize,
            height: avatarSize,
            borderRadius: "50%",
            overflow: "hidden",
            opacity: avatarProgress,
            transform: "scale(" + avatarScale + ")",
            flexShrink: 0
          }}>
            <Img 
              src={(props.profileImage ?? SCENE_PARAMS.profileImage.value)}
              style={{
                width: "100%",
                height: "100%",
                objectFit: "cover"
              }}
            />
          </div>
          
          {/* Name and Stats */}
          <div style={{ flex: 1, minWidth: 0 }}>
            {/* Name - nowrap to keep on single line */}
            <div style={{
              fontSize: minDim * 0.038,
              fontWeight: 700,
              color: (props.textColor ?? SCENE_PARAMS.textColor.value),
              fontFamily: (props.fontFamily ?? SCENE_PARAMS.fontFamily.value) + ", system-ui, sans-serif",
              opacity: nameProgress,
              transform: "translateY(" + slideUp(stagger) + "px)",
              marginBottom: minDim * 0.02,
              whiteSpace: "nowrap",
              overflow: "hidden",
              textOverflow: "ellipsis"
            }}>
              {(props.profileName ?? SCENE_PARAMS.profileName.value)}
            </div>
            
            {/* Stats Row */}
            <div style={{
              display: "flex",
              gap: minDim * 0.04,
              opacity: statsProgress,
              transform: "translateY(" + slideUp(stagger * 2) + "px)"
            }}>
              {[
                { num: (props.posts ?? SCENE_PARAMS.posts.value), label: "posts" },
                { num: (props.followers ?? SCENE_PARAMS.followers.value), label: "followers" },
                { num: (props.following ?? SCENE_PARAMS.following.value), label: "following" }
              ].map((stat, i) => (
                <div key={i} style={{ textAlign: "center" }}>
                  <div style={{
                    fontSize: minDim * 0.038,
                    fontWeight: 600,
                    color: (props.textColor ?? SCENE_PARAMS.textColor.value),
                    fontFamily: (props.fontFamily ?? SCENE_PARAMS.fontFamily.value) + ", system-ui, sans-serif"
                  }}>
                    {stat.num}
                  </div>
                  <div style={{
                    fontSize: minDim * 0.026,
                    fontWeight: 400,
                    color: (props.secondaryColor ?? SCENE_PARAMS.secondaryColor.value),
                    fontFamily: (props.fontFamily ?? SCENE_PARAMS.fontFamily.value) + ", system-ui, sans-serif"
                  }}>
                    {stat.label}
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
        
        {/* Bio */}
        <div style={{
          marginBottom: minDim * 0.05,
          opacity: bioProgress,
          transform: "translateY(" + slideUp(stagger * 4) + "px)"
        }}>
          {bioLines.map((line, i) => (
            <div key={i} style={{
              fontSize: minDim * 0.032,
              fontWeight: 400,
              color: (props.textColor ?? SCENE_PARAMS.textColor.value),
              fontFamily: (props.fontFamily ?? SCENE_PARAMS.fontFamily.value) + ", system-ui, sans-serif",
              lineHeight: 1.5
            }}>
              {line}
            </div>
          ))}
        </div>
        
        {/* Buttons */}
        <div style={{
          display: "flex",
          gap: minDim * 0.02,
          opacity: buttonsProgress,
          transform: "translateY(" + slideUp(stagger * 6) + "px)"
        }}>
          {[
            { text: "Follow", bg: (props.accentColor ?? SCENE_PARAMS.accentColor.value), color: "#ffffff" },
            { text: "Message", bg: (props.buttonBgColor ?? SCENE_PARAMS.buttonBgColor.value), color: (props.textColor ?? SCENE_PARAMS.textColor.value) },
            { text: "Email", bg: (props.buttonBgColor ?? SCENE_PARAMS.buttonBgColor.value), color: (props.textColor ?? SCENE_PARAMS.textColor.value) }
          ].map((btn, i) => (
            <div key={i} style={{
              flex: 1,
              backgroundColor: btn.bg,
              color: btn.color,
              padding: minDim * 0.022 + "px " + minDim * 0.03 + "px",
              borderRadius: minDim * 0.015,
              fontSize: minDim * 0.03,
              fontWeight: 600,
              fontFamily: (props.fontFamily ?? SCENE_PARAMS.fontFamily.value) + ", system-ui, sans-serif",
              textAlign: "center"
            }}>
              {btn.text}
            </div>
          ))}
        </div>
        
      </div>
    </AbsoluteFill>
  );
}

export default Scene;
